/*
Emitted when all active particles have finished processing. When [OneShot] is disabled, particles will process continuously, so this is never emitted.

[OneShot]: https://pkg.go.dev/graphics.gd/classdb/CPUParticles2D#Instance.OneShot
*/
func (self Instance) OnFinished(cb func(), flags ...Signal.Flags) Instance {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	gd.ObjectConnect(self.AsObject()[0], gd.NewStringName("finished"), gd.NewCallable(cb), int64(flags_together))
	return self
}

func (self class) Finished() Signal.Any {
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`finished`))))
}

